using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Common English stop words that carry little topical weight.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
        "that", "from", "as", "be", "been", "has", "have", "had", "do",
        "does", "did", "will", "would", "could", "should", "may", "might",
        "not", "no", "so", "if", "its", "he", "she", "they", "we", "you",
        "i", "me", "my", "your", "his", "her", "our", "their", "which",
        "what", "who", "whom", "how", "when", "where", "there", "then",
        "than", "also", "just", "about", "can", "into", "more", "some",
        "such", "very", "all", "each", "both", "few", "most", "other",
        "up", "out", "any", "only", "own", "same", "over", "after", "before"
    };

    /// <summary>
    /// Produces an extractive summary by scoring each sentence based on
    /// the frequency of its meaningful (non-stop) words and returning the
    /// top-ranked sentences in their original document order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
        {
            return string.Join(" ", sentences);
        }

        // Build a word-frequency map from non-stop words.
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
                }
            }
        }

        // Score each sentence by summing the frequencies of its content words.
        var scored = sentences
            .Select((text, index) => new
            {
                Text = text,
                Index = index,
                Score = Tokenize(text)
                    .Where(w => !StopWords.Contains(w))
                    .Sum(w => wordFrequency.GetValueOrDefault(w))
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Text);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static IEnumerable<string> Tokenize(string sentence)
    {
        return WordRegex()
            .Matches(sentence)
            .Select(m => m.Value.ToLowerInvariant());
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        var originalWordCount = request.DocumentText.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
        var summaryWordCount = summary.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = summaryWordCount
        });
    }
}

