+        "than", "also", "just", "about", "can", "into", "more", "some",
+        "such", "very", "all", "each", "both", "few", "most", "other",
+        "up", "out", "any", "only", "own", "same", "over", "after", "before"
+    };
+
+    /// <summary>
+    /// Produces an extractive summary by scoring each sentence based on
+    /// the frequency of its meaningful (non-stop) words and returning the
+    /// top-ranked sentences in their original document order.
+    /// </summary>
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitIntoSentences(documentText);
+
+        if (sentences.Count <= maxSentences)
+        {
+            return string.Join(" ", sentences);
+        }
+
+        // Build a word-frequency map from non-stop words.
+        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in Tokenize(sentence))
+            {
+                if (!StopWords.Contains(word))
+                {
+                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
+                }
+            }
+        }
+
+        // Score each sentence by summing the frequencies of its content words.
+        var scored = sentences
+            .Select((text, index) => new
+            {
+                Text = text,
+                Index = index,
+                Score = Tokenize(text)
+                    .Where(w => !StopWords.Contains(w))
+                    .Sum(w => wordFrequency.GetValueOrDefault(w))
+            })
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Text);
